const fs = require('fs');

const filePath = process.argv[2];
if (!filePath) {
  process.exit(1);
}

const buf = fs.readFileSync(filePath);

// Verify ELF magic
if (buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.exit(1);
}

const is64 = buf[4] === 2;
const isLE = buf[5] === 1;

if (!is64 || !isLE) {
  process.exit(1);
}

// ELF64 header fields (little-endian)
const e_phoff = Number(buf.readBigUInt64LE(32));
const e_phentsize = buf.readUInt16LE(54);
const e_phnum = buf.readUInt16LE(56);

const PT_LOAD = 1;
const result = {};

for (let i = 0; i < e_phnum; i++) {
  const off = e_phoff + i * e_phentsize;
  const p_type = buf.readUInt32LE(off);

  if (p_type !== PT_LOAD) continue;

  const p_offset = Number(buf.readBigUInt64LE(off + 8));
  const p_vaddr = Number(buf.readBigUInt64LE(off + 16));
  const p_filesz = Number(buf.readBigUInt64LE(off + 32));

  // Read 4-byte aligned values from this segment
  // Align start up to 4-byte boundary
  const startAddr = (p_vaddr + 3) & ~3;
  const alignOffset = startAddr - p_vaddr;

  for (let j = alignOffset; j + 4 <= p_filesz; j += 4) {
    const addr = p_vaddr + j;
    const fileOff = p_offset + j;

    if (fileOff + 4 > buf.length) break;

    const value = buf.readUInt32LE(fileOff);
    result[addr.toString()] = value;
  }
}

process.stdout.write(JSON.stringify(result) + '\n');

